module tcp_segmentation(  
    input [15:0] data_size,  
    input [15:0] mss,  
    output reg [3:0] num_segments  
);  
    always @(*) begin  
        if (data_size == 0)  
            num_segments = 0;  
        else if (data_size <= mss)  
            num_segments = 1;  
        else  
            num_segments = (data_size + mss - 1) / mss;  
    end  
endmodule
